type Manifest = { workspace?: { docs_directory?: string; projects_directory?: string; worktrees_directory?: string; setup?: string[]; cleanup?: string[] }; agents?: Record<string, { model?: string }>; subagents?: { async_by_default?: boolean; tool_description_mode?: "full" | "compact" | "custom"; completion_batch?: boolean; intercom_bridge_mode?: "always" | "fork-only" | "off"; supervisor_output?: "compact" | "full" }; pi?: { packages?: string[] }; permissions?: { default?: "allow" | "ask" | "deny"; shell?: "allow" | "ask" | "deny"; mcp?: "allow" | "ask" | "deny"; external_directories?: "allow" | "ask" | "deny" }; code_graph?: { server_name?: string; command?: string; args?: string[]; lifecycle?: string; idle_timeout?: number }; projects?: Array<{ name: string; path: string; repository?: string; default_branch?: string; depends_on?: string[]; ci?: string[]; setup?: string[]; cleanup?: string[] }> };

function isWorker() { return process.env.PI_SUBAGENT_CHILD === "1" && ["impl", "impl-lite"].includes(process.env.PI_SUBAGENT_CHILD_AGENT ?? ""); }
function isSubagent() { return process.env.PI_SUBAGENT_CHILD === "1"; }
function sessionId(ctx: ExtensionContext) { return process.env.PI_SUBAGENT_PARENT_SESSION || ctx.sessionManager.getSessionId() || "ephemeral"; }
function findRoot(cwd: string) { let current = path.resolve(cwd); while (true) { if (existsSync(path.join(current, "workspace.yaml"))) return current; const parent = path.dirname(current); if (parent === current) throw new Error("Pi Harness is not initialized here. Run the pi-harness initializer before opening Pi."); current = parent; } }
