  await writeFile(path.join(managed, "manifest.json"), JSON.stringify({ package: "pi-harness", version: packageVersion, generatedAt: new Date().toISOString() }, null, 2) + "\n");
  const settingFile = path.join(root, ".pi", "settings.json"); await mkdir(path.dirname(settingFile), { recursive: true });
  const current = existsSync(settingFile) ? JSON.parse(await readFile(settingFile, "utf8")) : {};
  const existingPackages = Array.isArray(current.packages) ? current.packages : [];
  const packages = [...existingPackages]; for (const source of [...REQUIRED_PI_PACKAGES, ...(config.pi?.packages ?? [])]) if (!packages.includes(source)) packages.push(source);
  const configured = config.agents ?? {}; const overrides = current.subagents?.agentOverrides ?? {};
