  await writeFile(settingFile, JSON.stringify({ ...current, ...(packages.length ? { packages } : {}), ...(configured.orchestrator?.model ? { defaultModel: configured.orchestrator.model } : {}), subagents: { ...(current.subagents ?? {}), agentOverrides: overrides } }, null, 2) + "\n");
  const subagents = config.subagents ?? {};
  const subagentConfigFile = path.join(root, ".pi", "extensions", "subagent", "config.json"); await mkdir(path.dirname(subagentConfigFile), { recursive: true });
  const currentSubagentConfig = existsSync(subagentConfigFile) ? JSON.parse(await readFile(subagentConfigFile, "utf8")) : {};
  await writeFile(subagentConfigFile, JSON.stringify({ ...currentSubagentConfig, asyncByDefault: subagents.async_by_default ?? true, toolDescriptionMode: subagents.tool_description_mode ?? "compact", completionBatch: { ...(currentSubagentConfig.completionBatch ?? {}), enabled: subagents.completion_batch ?? true }, control: { ...(currentSubagentConfig.control ?? {}), notifyOn: ["needs_attention"], notifyChannels: ["async"] }, intercomBridge: { ...(currentSubagentConfig.intercomBridge ?? {}), mode: subagents.intercom_bridge_mode ?? "always" } }, null, 2) + "\n");
  const graph = config.code_graph ?? {}; const mcpFile = path.join(root, ".mcp.json"); const mcp = existsSync(mcpFile) ? JSON.parse(await readFile(mcpFile, "utf8")) : {};
  const serverName = graph.server_name ?? "codebase-memory"; const graphProcess = bundledGraphCommand(graph);
