type SavedWorkflow = { root: string; state: WorkflowState };
function primaryWorkspaceRoot(root: string) { const common = git(root, ["rev-parse", "--path-format=absolute", "--git-common-dir"]); if (!common) return root; const candidate = path.dirname(path.resolve(root, common)); return existsSync(path.join(candidate, "workspace.yaml")) ? candidate : root; }
